import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int size = (int) n;
        List<List<long[]>> outgoing = new ArrayList<>(size);
        List<List<long[]>> incoming = new ArrayList<>(size);
        for (int i = 0; i < size; i++) {
            outgoing.add(new ArrayList<>());
            incoming.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long w = edge[2];
            outgoing.get((int) u).add(new long[] {(int) v, (int) w});
            incoming.get((int) v).add(new long[] {(int) u, (int) w});
        }

        long INF = Long.MAX_VALUE;
        long[][] dist = new long[size][2];
        for (int i = 0; i < size; i++) {
            dist[i][0] = INF;
            dist[i][1] = INF;
        }
        dist[0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[] {0, 0, 0});

        int target = size - 1;
        while (!pq.isEmpty()) {
            long cost = pq.peek()[0];
            int u = (int) pq.peek()[1];
            int s = pq.peek()[2];
            pq.poll();

            if (u == target) return cost;

            if (cost > dist[u][s]) continue;

            for (long[] edge : outgoing.get(u)) {
                int v = (int) edge[0];
                int wi = (int) edge[1];
                long newCost = cost + wi;
                if (newCost < dist[v][s]) {
                    dist[v][s] = newCost;
                    pq.offer(new long[] {newCost, v, s});
                }
            }

            if (s == 0) {
                for (long[] edge : incoming.get(u)) {
                    int v = (int) edge[0];
                    int wi = (int) edge[1];
                    long newCost = cost + 2 * wi;
                    if (newCost < dist[v][1]) {
                        dist[v][1] = newCost;
                        pq.offer(new long[] {newCost, v, 1});
                    }
                }
            }
        }

        long min = Long.MAX_VALUE;
        for (int s = 0; s < 2; s++) {
            if (dist[target][s] < min) min = dist[target][s];
        }
        return min == Long.MAX_VALUE ? -1 : min;
    }
}
